
















import { Component, Prop, Vue } from 'vue-property-decorator';
import VueGallery from 'vue-gallery';

import PlantListItem from '@/components/PlantListItem.vue';
import Editor from '@/components/Editor.vue';

import { IPlant } from '@/ts/plant';
import db from '@/ts/db';

const PAGE_SIZE = 20;

@Component({
  components: {
    PlantListItem,
    Editor,
    gallery: VueGallery,
  },
})
export default class PlantList extends Vue {

  @Prop({default: 1}) private page: number = 1;
  @Prop({default: 1}) private pageCount: number = 1;

  private plants: IPlant[] = [];
  private editing: IPlant | null = null;

  private galleryIndex: (number | null) = null;
  private galleryImages: any[] = [];

  private get pagePlants() {
    return this.plants.filter((_, index) => index >= (this.page - 1) * PAGE_SIZE && index < this.page * PAGE_SIZE );
  }

  private getPlantIndex(indexOnPage: number): number {
    return (this.page - 1) * PAGE_SIZE + indexOnPage + 1;
  }

  private edit(plant: IPlant) {
    this.editing = plant;
  }

  private update() {
    // console.log('updated');
  }

  private cancelEditing() {
    this.editing = null;
  }

  private mounted() {
    db.all().then((plants: IPlant[]) => {
      this.plants = plants.sort((a, b) => a.name.ru > b.name.ru ? 1 : -1);
      this.$emit('ready', { pageCount: Math.ceil(plants.length / PAGE_SIZE) } );
    });
  }
}
